#include <stdint.h>
#include <ctype.h>

int parse_int32(const char *s, int32_t *out)
{
    if (s == NULL || out == NULL)
        return 0;

    /* skip leading whitespace */
    while (isspace((unsigned char)*s))
        s++;

    if (*s == '\0')
        return 0;

    /* detect sign */
    int sign = 1;
    if (*s == '-') {
        sign = -1;
        s++;
    } else if (*s == '+') {
        s++;
    }

    if (*s == '\0')
        return 0;

    /* parse digits */
    int32_t acc = 0;
    int32_t limit = (sign == 1) ? INT32_MAX : INT32_MIN;

    while (isdigit((unsigned char)*s)) {
        int digit = *s - '0';

        /* check overflow before multiplying and adding */
        if (sign == 1) {
            if (acc > (INT32_MAX - digit) / 10)
                return 0;
        } else {
            /* INT32_MIN is -2147483648, so limit = -2147483648 */
            int32_t abs_limit = -(limit + 1); /* 2147483647 */
            if (acc > abs_limit / 10 ||
               (acc == abs_limit / 10 && digit > abs_limit % 10 + 1))
                return 0;
        }

        acc = acc * 10 + digit * sign;
        s++;
    }

    /* reject trailing non-whitespace */
    while (isspace((unsigned char)*s))
        s++;
    if (*s != '\0')
        return 0;

    *out = acc;
    return 1;
}

